blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>pięć podstawowych spójników</strong> języka angielskiego: i, ale, lub, ponieważ, więc — ich znaczenie i zasady użyj.",
    "rules": [
        {
            "label": "I",
            "color": "emerald",
            "text": "<strong>I, i</strong> — łączy podobne pomysły:",
            "example": "Lubię herbatę i kawę."
        },
        {
            "label": "Ale",
            "color": "rose",
            "text": "<strong>Ale jednak</strong> — pokazuje kontrast:",
            "example": "Lubię herbatę, ale nie lubię kawy: pada deszcz."
        },
        {
            "label": "Or",
            "color": "blue",
            "text": "<strong>Або</strong> — показує вибір:",
            "example": "Do you want tea or coffee?"
        },
        {
            "label": "Because",
            "color": "amber",
            "text": "<strong>Тому що</strong> — пояснює причину:",
            "example": "I stayed home because it was raining."
        },
        {
            "label": "Więc",
            "color": "purple",
            "text": "<strong>Dlatego</strong> - pokazuje wynik:",
            "example": "Deszcz padał, więc zostałem w domu."
        }
    ]
}

{
    "title": "1. Co to są spójniki?",
    "intro": "Spójniki to słowa, które łączą:",
    "items": [
        {
            "label": "Słowa",
            "title": "Słowa",
            "subtitle": "herbata i kawa / duże ale tanio"
        },
        {
            "label": "Zwroty",
            "title": "Zwroty",
            "subtitle": "rano lub wieczorem"
        },
        {
            "label": "Zwroty",
            "title": "Zdania",
            "subtitle": "Wróciłem do domu i Ugotowałem obiad."
        }
    ]
}

{
    "title": "2. AND — i, i (dodanie)",
    "sections": [
        {
            "label": "Wartość",
            "color": "emerald",
            "description": "<strong>I</strong> łączy podobne lub równoważne elementy. Dodaje informacje.",
            "examples": [
                {
                    "en": "Mam kota i psa.",
                    "ua": "Mam kota i psa."
                },
                {
                    "en": "Jest mądra i piękna.",
                    "ua": "Jest mądra i piękna."
                },
                {
                    "en": "Wróciłem do domu i oglądałem telewizję.[[[CODX_4]]]Wróciłem do domu i oglądałem telewizję.",
                    "ua": "Я прийшов додому і дивився телевізор."
                }
            ]
        },
        {
            "label": "Połącz słowa",
            "color": "sky",
            "description": "<strong>I</strong> mogą łączyć rzeczowniki, przymiotniki, czasowniki.",
            "examples": [
                {
                    "en": "chleb i masło",
                    "ua": "chleb i masło (rzeczowniki)"
                },
                {
                    "en": "duży i wygodny",
                    "ua": "duży i wygodny (przymiotniki)"
                },
                {
                    "en": "bieg i hop poszedł pobiegać.",
                    "ua": "бігати і стрибати (дієслова)"
                }
            ]
        },
        {
            "label": "Зʼєднання речень",
            "color": "amber",
            "description": "При зʼєднанні двох речень перед <strong>and</strong> часто ставиться кома.",
            "examples": [
                {
                    "en": "I woke up early, and I went for a run.",
                    "ua": "Я прокинувся рано і пішов на пробіжку."
                },
                {
                    "en": "Ona ugotowała obiad, a on umył naczynia.",
                    "ua": "Ona ugotowała obiad, a on umył naczynia."
                }
            ],
            "note": "Przecinek przed <strong>i</strong> jest opcjonalny, jeśli zdania są krótki."
        }
    ]
}

{
    "title": "3. ALE - ale jednak (kontrast)",
    "sections": [
        {
            "label": "Znaczenie[[[CODX_SEG_22]]<strong>Ale</strong> pokazuje kontrast, przeciwieństwo lub nieoczekiwany wynik.",
            "color": "rose",
            "description": "<strong>But</strong> показує контраст, протиставлення або несподіваний результат.",
            "examples": [
                {
                    "en": "Lubię kawę, ale nie lubię herbaty.",
                    "ua": "Lubię kawę, ale nie lubię herbata."
                },
                {
                    "en": "Jest młoda, ale bardzo doświadczona.",
                    "ua": "Jest młoda, ale bardzo doświadczona."
                },
                {
                    "en": "Starałem się, ale nie udało mi się dokończyć.",
                    "ua": "Próbowałem, ale nie udało mi się dokończyć."
                }
            ]
        },
        {
            "label": "Kontrast",
            "color": "sky",
            "description": "<strong>Ale</strong> wprowadza informacje sprzeczne z oczekiwaniami.",
            "examples": [
                {
                    "en": "Hotel był drogi, ale było warto.",
                    "ua": "Hotel był drogi, ale było warto."
                },
                {
                    "en": "Jest bogaty, ale nie jest szczęśliwy.",
                    "ua": "Jest bogaty, ale nie jest szczęśliwy."
                }
            ]
        },
        {
            "label": "Interpunkcja",
            "color": "amber",
            "description": "<strong>ale</strong> zwykle poprzedza się przecinkiem, gdy połączone są dwa pełne zdania.",
            "examples": [
                {
                    "en": "Chciałem iść, ale było zbyt późno.",
                    "ua": "Chciałem iść, ale było już za późno."
                }
            ],
            "note": "Bez przecinka: <em>mały, ale przytulny</em> (między słowami)."
        }
    ]
}

{
    "title": "4. LUB — lub (wybór)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "blue",
            "description": "<strong>Or</strong> pokazuje alternatywę, wybór pomiędzy opcjami.",
            "examples": [
                {
                    "en": "Chcesz herbatę czy kawę?",
                    "ua": "Chcesz herbatę czy kawę?"
                },
                {
                    "en": "Możemy iść dzisiaj lub jutro.",
                    "ua": "Możemy iść dzisiaj lub jutro."
                },
                {
                    "en": "Czy to prawda czy fałsz?",
                    "ua": "Czy to prawda czy fałsz?"
                }
            ]
        },
        {
            "label": "W pytaniach",
            "color": "sky",
            "description": "<strong>Or</strong> jest często używane w pytaniach, aby zasugerować wybór.",
            "examples": [
                {
                    "en": "Wolisz koty czy psy?",
                    "ua": "Wolisz koty czy psy?"
                },
                {
                    "en": "Mam do Ciebie zadzwonić lub wysłać SMS-a?",
                    "ua": "Mam do Ciebie zadzwonić lub wysłać SMS-a?"
                }
            ]
        },
        {
            "label": "W przeczenia",
            "color": "amber",
            "description": "W zdaniach przeczących często używa się słowa <strong>lub</strong> zamiast <strong>i</strong>.",
            "examples": [
                {
                    "en": "Nie lubię herbaty ani kawy.",
                    "ua": "Nie lubię herbaty ani kawy."
                },
                {
                    "en": "She doesn't eat meat or fish.",
                    "ua": "Вона не їсть мʼяса ні риби."
                }
            ],
            "note": "Порівняй: <em>I like tea <strong>and</strong> coffee</em> vs <em>I don't like tea <strong>or</strong> coffee</em>."
        }
    ]
}

{
    "title": "5. BECAUSE — тому що (причина)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "amber",
            "description": "<strong>Ponieważ</strong> wprowadza powód, wyjaśnia, dlaczego coś się wydarzyło.",
            "examples": [
                {
                    "en": "Zostałem w domu, bo padał deszcz.",
                    "ua": "Zostałem w domu, bo było pada deszcz."
                },
                {
                    "en": "Ona jest zmęczona, bo pracowała cały dzień.",
                    "ua": "Jest zmęczona, bo pracowała cały dzień."
                },
                {
                    "en": "Nie mogę przyjść, bo jestem zajęty.",
                    "ua": "Nie mogę przyjść, bo jestem zajęty."
                }
            ]
        },
        {
            "label": "Pozycja zdania",
            "color": "sky",
            "description": "Zdanie z <strong>ponieważ</strong> może znajdować się na początku lub na końcu.",
            "examples": [
                {
                    "en": "Zostałem w domu, bo padał deszcz.",
                    "ua": "(powód na koniec)"
                },
                {
                    "en": "Ponieważ padał deszcz, zostałem w domu.",
                    "ua": "(powód na początku jest przecinkiem)"
                }
            ]
        },
        {
            "label": "Ponieważ vs Z powodu",
            "color": "emerald",
            "description": "<strong>Ponieważ</strong> + zdanie, <strong>z powodu</strong> + rzeczownik.",
            "examples": [
                {
                    "en": "Zostałem w domu, bo padał deszcz.",
                    "ua": "(ponieważ + zdanie)"
                },
                {
                    "en": "Zostałem w domu, bo padał deszcz.",
                    "ua": "(ponieważ + rzeczownik)"
                }
            ],
            "note": "Nie mylić: <em>ponieważ</em> (ponieważ) vs <em>ponieważ</em> (do)."
        }
    ]
}

{
    "title": "6. SO - zatem (rezultat)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "purple",
            "description": "<strong>Tak</strong> wprowadza wynik, konsekwencję wcześniejszej akcji lub sytuacji.",
            "examples": [
                {
                    "en": "Deszcz padał, więc zostałem w domu.",
                    "ua": "Deszcz padał, więc zostałem w domu."
                },
                {
                    "en": "Byłem głodny, więc zrobiłem kanapkę.",
                    "ua": "Byłem głodny, więc zrobiłem kanapkę."
                },
                {
                    "en": "Ciężko się uczyła, więc zdała egzamin.",
                    "ua": "Ciężko się uczyła, więc zdała egzamin."
                }
            ]
        },
        {
            "label": "Ponieważ vs Tak",
            "color": "sky",
            "description": "<strong>Ponieważ</strong> = przyczyna, <strong>A więc</strong> = skutek. Te same informacje, inna kolejność.",
            "examples": [
                {
                    "en": "Zostałem w domu, bo padał deszcz.",
                    "ua": "(wynik + powód)"
                },
                {
                    "en": "Deszcz padał, więc zostałem w domu.",
                    "ua": "(powód + wynik)"
                }
            ]
        },
        {
            "label": "Interpunkcja",
            "color": "amber",
            "description": "Przed <strong>so</strong> zwykle następuje przecinek.",
            "examples": [
                {
                    "en": "Sklep był zamknięty, więc wróciliśmy do domu.",
                    "ua": "Sklep był zamknięty, więc poszliśmy domu."
                },
                {
                    "en": "Nie mam pieniędzy, więc nie mogę tego kupić.",
                    "ua": "Nie mam pieniędzy, więc nie mogę tego kupić."
                }
            ]
        }
    ]
}

{
    "title": "7. Tabela porównawcza",
    "intro": "Pięć podstawowych spójników i ich funkcje:",
    "rows": [
        {
            "en": "AND",
            "ua": "oraz",
            "note": "dodatek: lubię herbatę i kawa."
        },
        {
            "en": "ALE",
            "ua": "ale jednak",
            "note": "kontrast: lubię herbatę, ale nie lubię kawy."
        },
        {
            "en": "LUB[[CODX_SEG_26]]]lub",
            "ua": "або",
            "note": "wybór: Chcesz herbatę czy kawę?"
        },
        {
            "en": "PONIEWAŻ",
            "ua": "ponieważ",
            "note": "powod: zostałem w domu, bo było pada deszcz."
        },
        {
            "en": "SO",
            "ua": "więc",
            "note": "wynik: Padało, więc zostałem w domu."
        }
    ],
    "warning": "📌 <strong>I, ale, lub</strong> są spójnikami koordynującymi. <strong>Ponieważ, więc</strong> są podrzędne/wynikowe."
}

{
    "title": "8. Interpunkcja z spójnikami",
    "intro": "Kiedy stawiać przecinek przed spójnikiem:",
    "rows": [
        {
            "en": "Między słowami",
            "ua": "Między słowami",
            "note": "Bez przecinka: kawa i herbata, duże, ale tanie"
        },
        {
            "en": "Między klauzule",
            "ua": "Między zdaniami",
            "note": "Z przecinkiem: przyszedłem, a ona wyszła."
        },
        {
            "en": "Krótkie klauzule",
            "ua": "Krótkie klauzule",
            "note": "Przecinek jest opcjonalny: przyszedłem i ona lewy."
        }
    ],
    "warning": "⚠️ <strong>ale, więc</strong> przy łączeniu zdania zwykle poprzedza się przecinkiem."
}

{
    "title": "9. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomieszanie „ponieważ” i „ponieważ”.",
            "wrong": "Zostałem w domu, bo padał deszcz.",
            "right": "​​​​ <span class="font-mono">Zostałem w domu, bo padało pada deszcz.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie i zamiast lub w negatywach.",
            "wrong": "Nie lubię herbaty i kawy.",
            "right": "​​​​​​​​​ przecinki."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Because на початку без коми.",
            "wrong": "Ponieważ padał deszcz, zostałem w domu.",
            "right": "​​​​ <span class="font-mono">Ponieważ padał deszcz, zostałem w domu.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Więc zamiast tak (dla wynik).",
            "wrong": "Byłem zmęczony, więc poszedłem spać.",
            "right": "​​​​ <span class="font-mono">Byłem zmęczony, więc położyłem się spać.</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy spójnik",
    "select_intro": "Wpisz w puste miejsce odpowiedni spójnik.",
    "selects": [
        {
            "label": "Lubię herbatę ___ kawę. (i / ale / lub)",
            "prompt": "Jaki związek?"
        },
        {
            "label": "Ona jest mądra ___ niewiele się uczy. (i / ale / ponieważ)",
            "prompt": "Jaki związek?"
        },
        {
            "label": "Chcesz pizzę ___ makaron? (i / ale / lub)",
            "prompt": "Jaki związek?"
        },
        {
            "label": "Zostałem w domu ___ padał deszcz. (ale/ponieważ/tak) zdanie",
            "prompt": "Який сполучник?"
        }
    ],
    "options": [
        "and",
        "but",
        "or",
        "because",
        "so"
    ],
    "input_title": "Вправа 2. Зʼєднай речення",
    "input_intro": "Połącz dwa zdania odpowiednim spójnikiem.",
    "inputs": [
        {
            "before": "Byłem zmęczony. Poszedłem do łóżka. (więc) →",
            "after": ""
        },
        {
            "before": "Ona jest bogata. Ona nie jest szczęśliwa. (ale) →",
            "after": ""
        },
        {
            "before": "Nie mogę przyjść. Jestem zajęty. (ponieważ) →",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w użyciu spójnika.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Nie lubię herbaty i kawy.",
            "example_target": "Nie lubię herbaty ani kawy kawa."
        },
        {
            "original": "1. Zostałem w domu, bo było zimno.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Ponieważ byłem głodny, zrobiłem obiad. zdanie",
            "placeholder": "Виправ помилку (пунктуація)"
        }
    ]
}

{
    "title": "Інші сторінки з базової граматики",
    "items": [
        {
            "label": "Basic Conjunctions — and, but, or, because, so (поточна)",
            "current": true
        },
        {
            "label": "Imperatives — Наказові речення",
            "current": false
        },
        {
            "label": "Sentence Types — Види речень",
            "current": false
        },
        {
            "label": "Struktura zdania — Struktura zdania S–V–O ",
            "current": false
        },
        {
            "label": "Części mowy — Części mowy",
            "current": false
        }
    ]
}
